public static readonly LlamaLibrary.Logging.LLogger Log = new("ARR", Colors.DeepPink);

private static readonly string[] TutorialWindows =
{
    "HowToNotice",
    "HowTo",
    "PlayGuide",
    "JobHudNotice",
    "ContentsTutorial",
    "RecommendList",
    "AchievementInfo",
    "CreditScroll",
};



        bool hasTutorialWindow = TutorialWindows
            .Any(window => RaptureAtkUnitManager.GetWindowByName(window) != null);

        if (RaptureAtkUnitManager.GetWindowByName("CreditScroll") != null)
        {
            RaptureAtkUnitManager.GetWindowByName("CreditScroll").SendAction(1, 3uL, 0xFFFFFFFFuL);
        }

        if (RaptureAtkUnitManager.GetWindowByName("CreditPlayer") != null)
        {
            RaptureAtkUnitManager.GetWindowByName("CreditPlayer").SendAction(1, 3uL, 0xFFFFFFFFuL);
        }

        if (hasTutorialWindow)
        {
            await LlamaLibrary.Helpers.GeneralFunctions.CloseHowTos();
        }

			  return false;

        uint[] npcIds =
        {
            // Heavensward
            // Coerthas Western Highlands
            2005536,2006187,2006190,2006189,
            // Dravanian Forelands
            2006195,2006197,2006204,2006201,
            // Churning Mists
            2006216, 2006224, 2006217,2006218,
            // Sea of Clouds
            2006228, 2006229,2006234,2006231,
            // Dravanian Hinterlands
            20062808,2006205,2006210,2006214,

            // Stormblood
            // The Ruby Sea
            2007999, 2008002, 2007995, 2008004,
            // Yanxia
            2008008, 2008007, 2008011, 2008013,
            // The Azim Steppe
            2008015, 2008017, 2008019, 2008022,
            // The Fringes
            2007965, 2007967, 2007971, 2007972,
            // The Peaks
            2007978, 2007976, 2007981, 2007984,
            // The Lochs
            2007987, 2007992, 2007994, 2007993,

            // Dawntrail
            // Urqopacha
            2013924, 2013925, 2013929, 2013930, 2013926, 2013927, 2013928, 2013931, 2013932, 2013933,
            // Kozama'uka
            2013934, 2013935, 2013939, 2013940, 2013936, 2013937, 2013938, 2013941, 2013942, 2013943,
            // Yak T'el
            2013944, 2013945, 2013949, 2013950, 2013946, 2013947, 2013948, 2013951, 2013952, 2013953,
            // Shaaloani
            2013954, 2013955, 2013959, 2013960, 2013956, 2013957, 2013958, 2013961, 2013963, 2013962,
            // Heritage Found
            2013964, 2013965, 2013969, 2013970, 2013966, 2013967, 2013968, 2013971, 2013972, 2013973,
            // Living Memory
            2013974, 2013975, 2013979, 2013980, 2013976, 2013977, 2013978, 2013981, 2013982, 2013983,
        };
        var clickableAetherCurrent = GameObjectManager.GameObjects.Where(r =>  npcIds.Contains(r.NpcId) && r.IsTargetable && r.IsVisible && r.Distance2D(Core.Me.Location) < 100).OrderBy(r => r.Distance()).FirstOrDefault();

        if (clickableAetherCurrent != null && clickableAetherCurrent.IsValid)
        {
            Logging.WriteDiagnostic($"Moving to aethercurrent mob");
            while (Core.Me.Location.Distance2D(clickableAetherCurrent.Location) > 10f)
            {
                await LlamaLibrary.Helpers.Navigation.GroundMove(clickableAetherCurrent.Location, 10f);
            }
            Navigator.PlayerMover.MoveStop();
            await Coroutine.Wait(10000, () => Core.Me.InCombat);
            TreeRoot.Stop("Stopping to get aethercurrent");
        }
	return false;
